const _hoisted_81 = /* @__PURE__ */ createStaticVNode('<p>\u4ECE\u4EE5\u4E0A\u7684\u5B9E\u9A8C\u7ED3\u679C\u53EF\u4EE5\u770B\u51FA\uFF0C\u5373\u4F7F DOM \u6811\u4E0D\u5B8C\u6574\u3001CSSOM \u6811\u4E5F\u4E0D\u5B8C\u6574\uFF0C\u4F46\u9875\u9762\u91CC\u5916\u94FE CSS \u6587\u4EF6\u4E4B\u524D\u7684 DOM \u5143\u7D20\u4F9D\u7136\u8FDB\u884C\u4E86\u6E32\u67D3\u3002</p><p>\u4E3A\u4EC0\u4E48\u4F1A\u51FA\u73B0\u8FD9\u79CD\u60C5\u51B5\u5462\uFF1F\u603B\u7ED3\u6765\u8BF4\uFF1A</p><blockquote><p>An end tag whose tag name is &quot;script&quot;</p><p>...</p><ol><li>Let the script be the pending parsing-blocking script. There is no longer a pending parsing-blocking script.</li><li>Start the speculative HTML parser for this instance of the HTML parser.</li><li>Block the tokenizer for this instance of the HTML parser, such that the event loop will not run tasks that invoke the tokenizer.</li><li>If the parser&#39;s Document has a style sheet that is blocking scripts or the script&#39;s &quot;ready to be parser-executed&quot; flag is not set: spin the event loop until the parser&#39;s Document has no style sheet that is blocking scripts and the script&#39;s &quot;ready to be parser-executed&quot; flag is set.</li><li>If this parser has been aborted in the meantime, return.</li></ol><p>...</p></blockquote><p>\u5F53\u6D4F\u89C8\u5668\u4E3B\u7EBF\u7A0B\u89E3\u6790\u5230<code>&lt;/script&gt;</code>\u6807\u7B7E\u65F6\uFF0C\u82E5\u5F53\u524D\u6587\u6863\u5B58\u5728<strong>\u963B\u788D JS \u6267\u884C\u7684 CSS</strong>\u6216\u8005<strong>\u5F53\u524D\u7684\u811A\u672C\u4E0D\u5904\u4E8E<code>ready to be parser-executed</code>\u72B6\u6001</strong>\uFF0C\u5219<code>spin the event loop</code>\uFF0C\u76F4\u5230\u4E0D\u518D\u5B58\u5728\u963B\u788D JS \u6267\u884C\u7684 CSS \u4E14\u8BE5\u6BB5\u811A\u672C\u5904\u4E8E<code>ready to be parser-executed</code>\u3002</p><p>\u6211\u4EEC\u77E5\u9053\uFF0C\u5916\u94FE CSS \u6587\u4EF6\u7684\u52A0\u8F7D\u4F1A\u963B\u585E\u5176\u540E JavaScript \u6587\u4EF6\u7684\u6267\u884C\u3002\u800C\u811A\u672C\u4E0D\u5904\u4E8E<code>ready to be parser-executed</code>\u72B6\u6001\u662F\u6307\u811A\u672C\u8FD8\u6CA1\u52A0\u8F7D\u5B8C\u3002\u5982\u679C\u51FA\u73B0\u8FD9\u4E24\u79CD\u60C5\u51B5\uFF0C\u811A\u672C\u5C31\u6CA1\u6CD5\u7ACB\u5373\u6267\u884C\uFF0C\u9700\u8981\u7B49\u5F85\u5916\u94FE CSS \u6587\u4EF6\u52A0\u8F7D\u5B8C\u6210\u6216\u8005\u5916\u94FE JavaScript \u6587\u4EF6\u52A0\u8F7D\u5B8C\u6210\u3002\u6B64\u65F6\uFF0C\u6D4F\u89C8\u5668\u4F1A<code>spin the event loop</code>\uFF0C\u8BE5\u64CD\u4F5C\u5373\u4E3A\uFF1A</p><blockquote><p>\uFF08\u7B80\u5355\u7FFB\u8BD1\uFF0C\u5F85\u4FEE\u6539\uFF09</p><ol><li>\u6682\u5B58\u6B64\u65F6\u6B63\u5728\u6267\u884C\u7684 task \u6216 microtask</li><li>\u6682\u5B58\u6B64\u65F6\u7684 js \u6267\u884C\u4E0A\u4E0B\u6587\u5806\u6808</li><li>\u6E05\u7A7A js\u6267\u884C\u4E0A\u4E0B\u6587\u5806\u6808</li><li>\u5982\u679C\u5F53\u524D\u6B63\u5728\u6267\u884C\u7684\u662F task\uFF0C\u6267\u884C microtask checkpoint</li><li>\u505C\u6B62\u6267\u884C\u5F53\u524D\u7684 task/microtask\u3002\u7EE7\u7EED\u6267\u884C eventloop \u7684\u4E3B\u6D41\u7A0B\u3002</li><li>\u5F53\u6EE1\u8DB3\u6761\u4EF6\u65F6\uFF0C\u91CD\u65B0\u6DFB\u52A0\u4E4B\u524D\u6682\u5B58\u7684 task/microtask\uFF0C\u6062\u590D\u6682\u5B58\u7684 js \u6267\u884C\u4E0A\u4E0B\u6587\u5806\u6808\uFF0C\u7EE7\u7EED\u6267\u884C\u3002</li></ol></blockquote><p>\u7B80\u5355\u8BF4\u5C31\u662F\uFF0C\u8BA9<code>event loop</code>\u4E2D\u65AD\u5E76\u6682\u5B58\u5F53\u524D\u6B63\u5728\u6267\u884C\u7684<code>task</code>/<code>microtask</code>\uFF0C\u4FDD\u6301<code>event loop</code>\u7EE7\u7EED\u6267\u884C\uFF0C\u5F85\u4E00\u6BB5\u65F6\u95F4\u4E4B\u540E\u6EE1\u8DB3\u6761\u4EF6\u4E86\u518D\u6062\u590D\u4E4B\u524D\u7684<code>task</code>/<code>microtask</code>\u3002</p><p>\u56E0\u6B64\uFF0C\u8FD9\u4E2A\u95EE\u9898\u7684\u7B54\u6848\u5C31\u51FA\u6765\u4E86\uFF1A\u5982\u679C\u5728 HTML \u89E3\u6790\u8FC7\u7A0B\u4E2D\uFF0C\u89E3\u6790\u5230\u4E86\u67D0\u4E2A\u811A\u672C\u4F46\u8FD9\u4E2A\u811A\u672C\u88AB CSS \u963B\u585E\u4F4F\u4E86\u6216\u8005\u8FD8\u6CA1\u4E0B\u8F7D\u5B8C\uFF0C\u5219\u4F1A\u4E2D\u65AD\u6682\u5B58\u5F53\u524D\u7684\u89E3\u6790<code>task</code>\uFF0C\u7EE7\u7EED\u6267\u884C<code>event loop</code>\uFF0C\u7F51\u9875\u88AB\u6E32\u67D3\u3002\u5982\u679C JavaScript \u5168\u90E8\u662F\u5185\u8054\u7684\u6216\u8005\u7F51\u901F\u597D\uFF0C\u5728\u89E3\u6790\u5230<code>&lt;/script&gt;</code>\u65F6\u811A\u672C\u5168\u90FD\u5DF2\u4E0B\u8F7D\u5B8C\u4E86\uFF0C\u5219\u89E3\u6790<code>task</code>\u4E0D\u4F1A\u88AB\u4E2D\u65AD\uFF0C\u4E5F\u5C31\u4E0D\u4F1A\u51FA\u73B0\u6E32\u67D3\u60C5\u51B5\u4E86\u3002</p><h2 id="\u8D44\u6E90\u7684\u653E\u7F6E\u987A\u5E8F" tabindex="-1"><a class="header-anchor" href="#\u8D44\u6E90\u7684\u653E\u7F6E\u987A\u5E8F" aria-hidden="true">#</a> \u8D44\u6E90\u7684\u653E\u7F6E\u987A\u5E8F</h2><h3 id="\u4E3A\u4EC0\u4E48\u8981\u5C06\u5916\u94FE-javascript-\u6587\u4EF6\u653E\u5728\u6587\u6863\u5E95\u90E8" tabindex="-1"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u8981\u5C06\u5916\u94FE-javascript-\u6587\u4EF6\u653E\u5728\u6587\u6863\u5E95\u90E8" aria-hidden="true">#</a> \u4E3A\u4EC0\u4E48\u8981\u5C06\u5916\u94FE JavaScript \u6587\u4EF6\u653E\u5728\u6587\u6863\u5E95\u90E8</h3><p>\u5148\u8BF4\u7ED3\u8BBA\uFF1AJavaScript \u7684\u52A0\u8F7D\u548C\u6267\u884C\uFF0C\u4F1A\u963B\u585E JavaScript \u4E4B\u540E DOM \u8282\u70B9\u7684\u89E3\u6790\u548C\u6E32\u67D3\uFF0C\u4F46\u4E0D\u4F1A\u5F71\u54CD\u5176\u4E4B\u524D DOM \u8282\u70B9\u7684\u89E3\u6790\u548C\u6E32\u67D3\uFF0C\u56E0\u6B64\u8981\u5C06\u5916\u94FE JavaScript \u6587\u4EF6\u653E\u5230\u9875\u9762\u5C3D\u53EF\u80FD\u5E95\u90E8\u7684\u5730\u65B9\u3002</p><p>\u4F46\u662F\u8981\u5B8C\u5168\u5F04\u660E\u767D\u8FD9\u4E2A\u95EE\u9898\uFF0C\u5C31\u8981\u6DF1\u7A76\u4EE5\u4E0A\u7684\u7ED3\u8BBA\u3002</p><p>\u9996\u5148\uFF0CJavaScript \u7684\u52A0\u8F7D\u548C\u6267\u884C\uFF0C\u4E3A\u4EC0\u4E48\u4F1A\u963B\u585E\u5176\u4E4B\u540E DOM \u8282\u70B9\u7684\u89E3\u6790\u548C\u6E32\u67D3\u5462\uFF1F\u8FD9\u5B8C\u5168\u662F\u5386\u53F2\u539F\u56E0\u3002\u4EE5\u524D\u7684 JavaScript \u7ECF\u5E38\u5728\u6267\u884C\u7684\u65F6\u5019\u8FD0\u884C<code>document.write</code>\uFF08\u5F80\u6587\u6863\u91CC\u63D2\u5165\u5185\u5BB9\uFF09\uFF0C\u8FD9\u53EF\u80FD\u4F1A\u5BFC\u81F4\u5176\u540E DOM \u8282\u70B9\u5B8C\u5168\u53D1\u751F\u53D8\u5316\uFF0C\u56E0\u6B64\u65E0\u6CD5\u5B89\u5168\u5730\u5728 JavaScript \u6267\u884C\u7684\u540C\u65F6\u6765\u6E32\u67D3 DOM \u8282\u70B9\u3002</p><div class="custom-container tip"><p class="custom-container-title">\u76F8\u5173\u77E5\u8BC6\u70B9</p><p><code>document.write</code>\u65B9\u6CD5\u5C06\u4E00\u4E2A\u6587\u672C\u5B57\u7B26\u4E32\u5199\u5165\u4E00\u4E2A\u7531<code>document.open()</code>\u6253\u5F00\u7684\u6587\u6863\u6D41\uFF08document stream\uFF09\u3002</p><p>\u82E5\u5411\u4E00\u4E2A\u5DF2\u7ECF\u52A0\u8F7D\u4E14\u6CA1\u6709\u8C03\u7528\u8FC7<code>document.open()</code>\u7684\u6587\u6863\u5199\u5165\u6570\u636E\u65F6\uFF0C\u4F1A\u81EA\u52A8\u8C03\u7528<code>document.open</code>\u3002\u4E00\u65E6\u5B8C\u6210\u4E86\u6570\u636E\u5199\u5165\uFF0C\u5EFA\u8BAE\u8C03\u7528<code>document.close()</code>\uFF0C\u4EE5\u544A\u8BC9\u6D4F\u89C8\u5668\u5F53\u524D\u9875\u9762\u5DF2\u7ECF\u52A0\u8F7D\u5B8C\u6BD5\u3002\u5199\u5165\u7684\u6570\u636E\u4F1A\u88AB\u89E3\u6790\u5230\u6587\u6863\u7ED3\u6784\u6A21\u578B\uFF08DOM\uFF09\u91CC\uFF0C\u5B8C\u5168\u8986\u76D6\u5F53\u9762\u7684\u6587\u6863\uFF08\u5373<code>&lt;html&gt;</code>\u6807\u7B7E\u5185\u7684\u5185\u5BB9\u90FD\u88AB\u66FF\u6362\uFF09\u3002</p><p>\u82E5<code>document.write</code>\u662F\u5728\u9875\u9762\u7684<code>&lt;script&gt;&lt;/script&gt;</code>\u91CC\u540C\u6B65\u8C03\u7528\u7684\uFF08\u8BF4\u660E\u5F53\u524D\u6587\u6863\u8FD8\u672A\u5B8C\u6210\u52A0\u8F7D\uFF09\uFF0C\u5219\u5B83\u5C06\u4E0D\u4F1A\u81EA\u52A8\u8C03\u7528<code>document.open()</code>\uFF0C\u4E14\u6B64\u65F6\u901A\u8FC7<code>document.write</code>\u5199\u5165\u7684\u5185\u5BB9\u4F1A\u8FFD\u52A0\u5728\u5F53\u524D\u6587\u6863\u91CC\u3002</p></div><p>\u73B0\u5728\u7684\u6D4F\u89C8\u5668\u90FD\u652F\u6301<code>async</code>\u6216\u8005<code>defer</code>\u5C5E\u6027\u4E86\uFF0C\u8BF4\u660E\u811A\u672C\u975E\u963B\u585E\u5176\u5B9E\u4E00\u70B9\u95EE\u9898\u90FD\u6CA1\u6709\uFF0C\u800C\u811A\u672C\u963B\u585E\u5C31\u662F\u5386\u53F2\u539F\u56E0\u5BFC\u81F4\u7684\u517C\u5BB9\u6027\u95EE\u9898\u3002</p><p>\u6B63\u662F\u56E0\u4E3A JavaScript \u7684\u52A0\u8F7D\u548C\u6267\u884C\u4F1A\u963B\u585E\u5176\u540E DOM \u8282\u70B9\u7684\u89E3\u6790\u548C\u6E32\u67D3\uFF0C\u56E0\u6B64\u82E5\u662F\u5C06\u5916\u94FE JavaScript \u6587\u4EF6\u7F6E\u4E8E\u6587\u6863\u9876\u90E8\u4F1A\u5BFC\u81F4\u9996\u5C4F\u767D\u5C4F\u65F6\u95F4\u589E\u52A0\uFF1B\u7F6E\u4E8E\u6587\u6863\u4E2D\u90E8\uFF0C\u53EF\u80FD\u4F1A\u5BFC\u81F4\u9875\u9762\u53EA\u6E32\u67D3\u4E00\u90E8\u5206 DOM \u540E\u963B\u585E\u6E32\u67D3\u540E\u4E00\u90E8\u5206 DOM\u3002\u56E0\u6B64\uFF0C\u5C06\u5916\u94FE JavaScript \u6587\u4EF6\u7F6E\u4E8E\u6587\u6863\u5C3D\u53EF\u80FD\u5E95\u90E8\u7684\u5730\u65B9\u662F\u6700\u4F18\u7684\u65B9\u5F0F\u3002</p><h3 id="\u4E3A\u4EC0\u4E48\u8981\u5C06-css-\u653E\u5728-head-\u6807\u7B7E\u91CC" tabindex="-1"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u8981\u5C06-css-\u653E\u5728-head-\u6807\u7B7E\u91CC" aria-hidden="true">#</a> \u4E3A\u4EC0\u4E48\u8981\u5C06 CSS \u653E\u5728 head \u6807\u7B7E\u91CC</h3><p>\u82E5\u662F\u5C06 CSS\uFF08\u5305\u62EC<code>style</code>\u6807\u7B7E\u5185\u7684\u5185\u90E8\u6837\u5F0F\u548C\u5916\u94FE CSS \u6837\u5F0F\u8868\uFF0C\u4E0B\u540C\uFF09\u653E\u5728\u9875\u9762\u5E95\u90E8\u5373<code>&lt;/body&gt;</code>\u4E4B\u524D\uFF0C\u6D4F\u89C8\u5668\u4F1A\u5148\u89E3\u6790 HTML \u5E76\u6784\u5EFA DOM \u6811\uFF0C\u89E3\u6790\u5230\u6587\u4EF6\u5E95\u90E8 CSS \u6240\u5728\u4F4D\u7F6E\u65F6\uFF0CDOM \u6811\u57FA\u672C\u6784\u5EFA\u5B8C\u6210\uFF0C\u800C\u6B64\u65F6\u624D\u5F00\u59CB\u6784\u5EFA CSSOM \u6811\uFF0C\u5BFC\u81F4 DOM \u6811\u7684\u6784\u5EFA\u548C CSSOM \u6811\u7684\u6784\u5EFA\u57FA\u672C\u4E0A\u662F\u4E32\u884C\u7684\u3002\u800C\u4E14\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u5E95\u90E8\u7684\u5916\u94FE CSS \u6587\u4EF6\u52A0\u8F7D\u65F6\uFF0C\u6D4F\u89C8\u5668\u4F1A\u5148\u6E32\u67D3\u51FA\u4E00\u4E2A\u6CA1\u6709\u6837\u5F0F\u7684\u9875\u9762\uFF08\u5185\u8054\u6837\u5F0F\u4E0D\u4F1A\u6E32\u67D3\uFF0C\u5426\u5219\u7B49\u5916\u94FE CSS \u6587\u4EF6\u52A0\u8F7D\u597D\u540E\uFF0C\u53C8\u8981\u7ED3\u5408\u5168\u90E8\u6837\u5F0F\u518D\u6E32\u67D3\u4E00\u6B21\uFF09\uFF0C\u7B49\u5916\u94FE CSS \u6587\u4EF6\u52A0\u8F7D\u5B8C\u540E\u4F1A\u518D\u6E32\u67D3\u6210\u4E00\u4E2A\u6709\u6837\u5F0F\u7684\u9875\u9762\uFF0C\u9875\u9762\u4F1A\u51FA\u73B0\u660E\u663E\u7684\u95EA\u52A8\u7684\u73B0\u8C61\u3002</p><p>\u800C\u5C06 CSS \u653E\u5728<code>head</code>\u6807\u7B7E\u4E4B\u95F4\uFF0CCSSOM \u6811\u7684\u6784\u5EFA\u53EF\u4EE5\u66F4\u65E9\u5730\u8FDB\u884C\uFF0C\u6700\u7EC8\u9875\u9762\u4E5F\u80FD\u66F4\u65E9\u5730\u8FDB\u884C\u9996\u6B21\u6E32\u67D3\u3002</p><h2 id="domcontentloaded-\u548C-load-\u4E8B\u4EF6\u7684\u89E6\u53D1\u65F6\u673A" tabindex="-1"><a class="header-anchor" href="#domcontentloaded-\u548C-load-\u4E8B\u4EF6\u7684\u89E6\u53D1\u65F6\u673A" aria-hidden="true">#</a> DOMContentLoaded \u548C load \u4E8B\u4EF6\u7684\u89E6\u53D1\u65F6\u673A</h2><p>MDN \u7684\u89E3\u91CA\uFF1A</p><blockquote><p>\u5F53\u521D\u59CB\u7684 HTML \u6587\u6863\u88AB\u5B8C\u5168\u52A0\u8F7D\u548C\u89E3\u6790\u5B8C\u6210\u4E4B\u540E\uFF0C<code>DOMContentLoaded</code>\u4E8B\u4EF6\u88AB\u89E6\u53D1\uFF0C\u800C\u65E0\u9700\u7B49\u5F85\u6837\u5F0F\u8868\u3001\u56FE\u50CF\u548C\u5B50\u6846\u67B6\u7684\u5B8C\u6210\u52A0\u8F7D\u3002\u6CE8\u610F: <code>DOMContentLoaded</code>\u4E8B\u4EF6\u5FC5\u987B\u7B49\u5F85\u5176\u6240\u5C5E<code>script</code>\u4E4B\u524D\u7684\u6837\u5F0F\u8868\u52A0\u8F7D\u89E3\u6790\u5B8C\u6210\u624D\u4F1A\u89E6\u53D1\u3002</p><p>\u6574\u4E2A\u9875\u9762\u52A0\u8F7D\u5B8C\u6210\u4E4B\u540E\uFF0C\u5305\u62EC\u6240\u6709\u4F9D\u8D56\u7684\u8D44\u6E90\u6BD4\u5982\u6837\u5F0F\u8868\u548C\u56FE\u7247\uFF0C<code>load</code>\u4E8B\u4EF6\u88AB\u89E6\u53D1\u3002</p></blockquote><p>MDN \u7684\u89E3\u91CA\u5E76\u4E0D\u662F\u90A3\u4E48\u5730\u6E05\u695A\uFF0C\u4ECE\u4E0A\u4E00\u8282\u201C\u9875\u9762\u9996\u6B21\u6E32\u67D3\u201D\u6765\u770B:</p><ul><li>HTML \u6587\u6863\u52A0\u8F7D\u5B8C\u6BD5\uFF0C\u4E14 HTML \u91CC\u5F15\u7528\u7684\u5185\u8054 JavaScript \u548C\u5916\u94FE JavaScript \u6587\u4EF6\u90FD\u52A0\u8F7D\u5B8C\u6210\u5E76\u6267\u884C\u5B8C\u6210\u4E4B\u540E\uFF0C\u89E6\u53D1<code>DOMContentLoaded</code>\u4E8B\u4EF6\u3002 <ul><li>\u6CE8\u610F: <code>DOMContentLoaded</code>\u4E8B\u4EF6\u5FC5\u987B\u7B49\u5F85\u5176\u6240\u5C5E<code>script</code>\u4E4B\u524D\u7684\u6837\u5F0F\u8868\u52A0\u8F7D\u89E3\u6790\u5B8C\u6210\u624D\u4F1A\u89E6\u53D1\u3002</li><li>\u6CE8\u610F: \u82E5\u662F\u5916\u94FE JavaScript \u6587\u4EF6\u4E14\u5B58\u5728<code>defer</code>\u5C5E\u6027\uFF0C\u5219\u4F1A\u5728\u8BE5\u6587\u4EF6\u52A0\u8F7D\u6267\u884C\u5B8C\u6210\u4E4B\u540E\uFF0C\u624D\u4F1A\u89E6\u53D1<code>DOMContentLoaded</code>\u4E8B\u4EF6\u3002</li></ul></li><li>HTML \u6587\u6863\u91CC\u5F15\u7528\u7684 JavaScript \u6587\u4EF6\u3001CSS \u6587\u4EF6\u3001\u56FE\u7247\uFF0C\u4EE5\u53CA JavaScript \u4EE3\u7801\u91CC\u5F02\u6B65\u52A0\u8F7D\u7684 JavaScript\u3001CSS \u548C\u56FE\u7247\u90FD\u52A0\u8F7D\u5B8C\u6210\u4E4B\u540E\uFF0C\u89E6\u53D1<code>load</code>\u4E8B\u4EF6\u3002\u6CE8\u610F: <ul><li>HTML \u6587\u6863\u91CC\u5F15\u7528\u7684 JavaScript \u4EE3\u7801\u91CC\u82E5\u662F\u6709\u5F02\u6B65\u52A0\u8F7D\u7684 JavaScript\u3001CSS\u3001\u56FE\u7247\uFF0C\u662F\u4F1A\u5F71\u54CD<code>load</code>\u4E8B\u4EF6\u89E6\u53D1\u7684\u3002</li><li><code>video</code>\u3001<code>audio</code>\u3001<code>flash</code>\u4E0D\u4F1A\u5F71\u54CD<code>load</code>\u4E8B\u4EF6\u89E6\u53D1\u3002</li></ul></li></ul><h2 id="\u6D4F\u89C8\u5668\u4E0B\u8F7D\u5E76\u53D1\u6570" tabindex="-1"><a class="header-anchor" href="#\u6D4F\u89C8\u5668\u4E0B\u8F7D\u5E76\u53D1\u6570" aria-hidden="true">#</a> \u6D4F\u89C8\u5668\u4E0B\u8F7D\u5E76\u53D1\u6570</h2>', 25);
